Create `apps/client/src/layers/features/chat/model/use-background-tasks.ts` to replace `use-running-subagents.ts`. This hook derives visible background tasks from messages, applies the 5-second threshold for bash tasks, manages celebration windows, and assigns stable colors.

## Implementation

Create `apps/client/src/layers/features/chat/model/use-background-tasks.ts`:

```typescript
import { useMemo, useRef, useState, useEffect } from 'react';
import type { BackgroundTaskPart } from '@dorkos/shared/types';
import type { ChatMessage } from './chat-types';

export interface VisibleTask {
  taskId: string;
  taskType: 'agent' | 'bash';
  status: 'running' | 'complete' | 'error' | 'stopped';
  color: string;
  startedAt: number;
  // Agent-specific
  description?: string;
  toolUses?: number;
  lastToolName?: string;
  durationMs?: number;
  summary?: string;
  // Bash-specific
  command?: string;
}

export const TASK_COLORS = [
  'hsl(210 80% 60%)', // blue
  'hsl(150 60% 50%)', // green
  'hsl(270 60% 65%)', // purple
  'hsl(36 90% 55%)',  // amber
  'hsl(340 75% 60%)', // rose
] as const;

/** Minimum time (ms) a bash task must run before appearing in the bar. */
const BASH_VISIBILITY_THRESHOLD_MS = 5000;

/** Re-evaluation interval for pending bash tasks below the threshold. */
const BASH_TIMER_INTERVAL_MS = 1000;

/** Celebration window duration in milliseconds. */
const CELEBRATION_DURATION_MS = 1500;

/**
 * Derive visible background tasks from the message stream.
 *
 * Agent tasks appear immediately. Bash tasks only appear after running for
 * 5 seconds to avoid UI churn from quick commands. Completed tasks remain
 * visible for 1500ms (celebration window) before removal.
 */
export function useBackgroundTasks(messages: ChatMessage[]): VisibleTask[] {
  const colorMapRef = useRef<Map<string, string>>(new Map());
  const colorIndexRef = useRef(0);
  const prevStatusRef = useRef<Map<string, string>>(new Map());
  const celebratingRef = useRef<Set<string>>(new Set());
  const [, setRenderTick] = useState(0);

  // Collect the latest background task part per taskId across all messages
  const taskMap = useMemo(() => {
    const map = new Map<string, BackgroundTaskPart>();
    for (const message of messages) {
      for (const part of message.parts) {
        if (part.type === 'background_task') {
          map.set(part.taskId, part);
        }
      }
    }
    return map;
  }, [messages]);

  // Timer for re-evaluating bash tasks below the 5s threshold
  useEffect(() => {
    const hasPendingBash = Array.from(taskMap.values()).some(
      (t) =>
        t.taskType === 'bash' &&
        t.status === 'running' &&
        Date.now() - t.startedAt < BASH_VISIBILITY_THRESHOLD_MS
    );

    if (!hasPendingBash) return;

    const interval = setInterval(() => {
      setRenderTick((t) => t + 1);
    }, BASH_TIMER_INTERVAL_MS);

    return () => clearInterval(interval);
  }, [taskMap]);

  // Detect status transitions and manage celebration windows
  useEffect(() => {
    const timers: ReturnType<typeof setTimeout>[] = [];

    for (const [taskId, part] of taskMap) {
      const prevStatus = prevStatusRef.current.get(taskId);
      const justCompleted =
        prevStatus === 'running' &&
        (part.status === 'complete' || part.status === 'error' || part.status === 'stopped');

      if (justCompleted && !celebratingRef.current.has(taskId)) {
        celebratingRef.current.add(taskId);
        const timer = setTimeout(() => {
          celebratingRef.current.delete(taskId);
          setRenderTick((t) => t + 1);
        }, CELEBRATION_DURATION_MS);
        timers.push(timer);
      }

      prevStatusRef.current.set(taskId, part.status);
    }

    return () => {
      for (const timer of timers) clearTimeout(timer);
    };
  }, [taskMap]);

  // Build the result array
  return useMemo(() => {
    const now = Date.now();
    const result: VisibleTask[] = [];

    for (const [taskId, part] of taskMap) {
      const isRunning = part.status === 'running';
      const isCelebrating = celebratingRef.current.has(taskId);

      if (!isRunning && !isCelebrating) continue;

      // Apply 5-second threshold for bash tasks
      if (
        part.taskType === 'bash' &&
        isRunning &&
        now - part.startedAt < BASH_VISIBILITY_THRESHOLD_MS
      ) {
        continue;
      }

      // Assign stable color from shared pool
      if (!colorMapRef.current.has(taskId)) {
        colorMapRef.current.set(
          taskId,
          TASK_COLORS[colorIndexRef.current % TASK_COLORS.length]
        );
        colorIndexRef.current += 1;
      }

      result.push({
        taskId: part.taskId,
        taskType: part.taskType,
        status: part.status,
        color: colorMapRef.current.get(taskId)!,
        startedAt: part.startedAt,
        description: part.description,
        toolUses: part.toolUses,
        lastToolName: part.lastToolName,
        durationMs: part.durationMs,
        summary: part.summary,
        command: part.command,
      });
    }

    return result;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [taskMap /* renderTick drives re-computation via state change */]);
}
```

Update the barrel export in `apps/client/src/layers/features/chat/index.ts` (if applicable) to export `useBackgroundTasks` and `VisibleTask` instead of `useRunningSubagents` and `RunningAgent`.

## Acceptance Criteria
- Agent tasks appear immediately in the result array when status is `'running'`
- Bash tasks only appear after `startedAt + 5000ms < Date.now()`
- A 1-second interval timer re-evaluates pending bash tasks; the timer only runs when there are pending bash tasks below the threshold
- The timer is cleared on unmount and when no pending bash tasks remain
- Completed/error/stopped tasks remain visible for 1500ms (celebration window)
- Colors are assigned from a shared 5-color pool (`TASK_COLORS`) and are stable across re-renders
- The hook returns `VisibleTask[]` with all fields needed by both agent and bash UI components
- The `'stopped'` status is recognized and handled (triggers celebration window like `'complete'` and `'error'`)

