Create `apps/client/src/layers/features/chat/ui/BackgroundTaskBar.tsx` as the unified bar component that replaces `RunningAgentIndicator.tsx`. This component renders agent runners alongside bash task dots with an expand toggle.

## Implementation

Create `apps/client/src/layers/features/chat/ui/BackgroundTaskBar.tsx`:

```typescript
import { useState } from 'react';
import { AnimatePresence, motion, useReducedMotion } from 'motion/react';
import { ChevronDown } from 'lucide-react';
import { cn } from '@/layers/shared/lib';
import type { VisibleTask } from '../model/use-background-tasks';
import { AgentRunner } from './AgentRunner';
import { TaskDotSection } from './TaskDotSection';
import { TaskDetailPanel } from './TaskDetailPanel';

interface BackgroundTaskBarProps {
  tasks: VisibleTask[];
  onStopTask: (taskId: string) => void;
}

/** Maximum number of agent runner figures to render before overflow. */
const MAX_VISIBLE_AGENTS = 4;

/** Unified bar showing running background agents and bash task dots with expandable detail panel. */
export function BackgroundTaskBar({ tasks, onStopTask }: BackgroundTaskBarProps) {
  const [isExpanded, setIsExpanded] = useState(false);
  const prefersReducedMotion = useReducedMotion();

  const agentTasks = tasks.filter((t) => t.taskType === 'agent');
  const bashTasks = tasks.filter((t) => t.taskType === 'bash');
  const count = tasks.length;

  const visibleAgents = agentTasks.slice(0, MAX_VISIBLE_AGENTS);
  const overflowAgentCount = agentTasks.length - MAX_VISIBLE_AGENTS;

