import type { HistoryMessage, MessagePart, BackgroundTaskPart } from '@dorkos/shared/types';

/** Map a server `HistoryMessage` to the client `ChatMessage` format. */
export function mapHistoryMessage(m: HistoryMessage): ChatMessage {
  const parts: MessagePart[] = m.parts ? m.parts.map(migratePart) : [];
  // ... rest of existing logic ...
}

/**
 * Migrate a legacy SubagentPart to BackgroundTaskPart.
 *
 * Old JSONL transcripts contain parts with `type: 'subagent'`. The current
 * schema uses `type: 'background_task'`. This function converts on read.
 */
function migratePart(part: MessagePart | Record<string, unknown>): MessagePart {
  if ((part as Record<string, unknown>).type === 'subagent') {
    const legacy = part as Record<string, unknown>;
    return {
      type: 'background_task',
      taskId: legacy.taskId as string,
      taskType: 'agent',
      status: legacy.status === 'running' ? 'running'
            : legacy.status === 'complete' ? 'complete'
            : legacy.status === 'error' ? 'error'
            : 'error',
      startedAt: 0, // Not available in old format
      description: legacy.description as string | undefined,
      toolUses: legacy.toolUses as number | undefined,
      lastToolName: legacy.lastToolName as string | undefined,
      durationMs: legacy.durationMs as number | undefined,
      summary: legacy.summary as string | undefined,
    } as BackgroundTaskPart;
  }
  return part as MessagePart;
}
