    await request(app)
      .post(`/api/sessions/${sessionId}/tasks/${taskId}/stop`)
      .expect(404);
  });

  it('returns 400 for invalid session ID', async () => {
    await request(app)
      .post('/api/sessions/not-a-uuid/tasks/task-1/stop')
      .expect(400);
  });
